module binary_adder_4bit(
    input   [3:0]   a     ,
    input   [3:0]   b     ,

    output  [3:0]   sum   ,
    output          carry_out
);

   // Internal wire for carry
   wire [4:0] sum_total;

   // Perform the addition
   assign sum_total = a + b;

   // Assign the outputs
   assign sum = sum_total[3:0];
   assign carry_out = sum_total[4];

endmodule
